    const min = this.data[0];
    const last = this.data.pop()!;
    if (this.data.length > 0) {
      this.data[0] = last;
      let i = 0;
      while (true) {
        let s = i, l = 2*i+1, r = 2*i+2;
        if (l < this.data.length && this.data[l] < this.data[s]) s = l;
        if (r < this.data.length && this.data[r] < this.data[s]) s = r;
