function topK(nums: number[], k: number): number[] {
  const heap = new MinHeap();
  for (const n of nums) {
    heap.push(n);
    if (heap.size > k) heap.pop();
  }
  const result: number[] = [];
  while (heap.size > 0) result.push(heap.pop()!);
  return result.sort((a, b) => b - a);
}

