class MinHeap {
  private data: [number, number, number][] = [];
  get size() { return this.data.length; }
  push(val: [number, number, number]) {
    this.data.push(val);
    let i = this.data.length - 1;
    while (i > 0) {
      const p = Math.floor((i - 1) / 2);
      if (this.data[p][0] <= this.data[i][0]) break;
      [this.data[p], this.data[i]] = [this.data[i], this.data[p]];
      i = p;
    }
  }
  pop(): [number, number, number] {
    const min = this.data[0]; const last = this.data.pop()!;
    if (this.data.length > 0) {
      this.data[0] = last; let i = 0;
      while (true) {
        let s = i, l = 2*i+1, r = 2*i+2;
        if (l < this.data.length && this.data[l][0] < this.data[s][0]) s = l;
        if (r < this.data.length && this.data[r][0] < this.data[s][0]) s = r;
        if (s === i) break;
        [this.data[s], this.data[i]] = [this.data[i], this.data[s]]; i = s;
      }
    }
    return min;
  }
}

function mergeKSorted(arrays: number[][]): number[] {
  const heap = new MinHeap();
  for (let i = 0; i < arrays.length; i++) {
    if (arrays[i].length > 0) heap.push([arrays[i][0], i, 0]);
  }
  const result: number[] = [];
  while (heap.size > 0) {
    const [val, arrIdx, elemIdx] = heap.pop();
    result.push(val);
    if (elemIdx + 1 < arrays[arrIdx].length) {
      heap.push([arrays[arrIdx][elemIdx + 1], arrIdx, elemIdx + 1]);
    }
  }
  return result;
}

console.log(mergeKSorted([[1,4,7],[2,5,8],[3,6,9]]));  // [1,2,3,4,5,6,7,8,9]

